        let transformed = scale.transform(&data).unwrap();

        // Check that columns have unit variance
        for col in 0..transformed.ncols() {
            let col_std = transformed.column(col).std(1.0);
            assert_abs_diff_eq!(col_std, 1.0, epsilon = 1e-10);
        }

        // Check inverse transform
        let recovered = scale.inverse_transform(&transformed).unwrap();
        assert_abs_diff_eq!(recovered, data, epsilon = 1e-10);
    }

