            let col_std = transformed.column(col).std(1.0);
            assert_abs_diff_eq!(col_mean, 0.0, epsilon = 1e-10);
            assert_abs_diff_eq!(col_std, 1.0, epsilon = 1e-10);
        }

        // Check inverse transform
        let recovered = pipeline.inverse_transform(&transformed).unwrap();
        assert_abs_diff_eq!(recovered, data, epsilon = 1e-10);
    }
}

